import{_ as i,o as e,c as t,ag as r}from"./chunks/framework.BuUvxvtQ.js";const _=JSON.parse('{"title":"Почему важна защита аккаунтов","description":"","frontmatter":{},"headers":[],"relativePath":"importance.md","filePath":"importance.md"}'),l={name:"importance.md"};function o(c,a,s,d,n,p){return e(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="почему-важна-защита-аккаунтов" tabindex="-1">Почему важна защита аккаунтов <a class="header-anchor" href="#почему-важна-защита-аккаунтов" aria-label="Permalink to &quot;Почему важна защита аккаунтов&quot;">​</a></h1><p>Аккаунт в социальной сети давно перестал быть просто страницей для общения. Он часто связан с номером телефона, электронной почтой, фотографиями, архивом сообщений, платежными инструментами, рабочими контактами и личными документами, которые случайно могли оказаться в переписке.</p><h2 id="какие-риски-возникают-при-слабои-защите" tabindex="-1">Какие риски возникают при слабой защите <a class="header-anchor" href="#какие-риски-возникают-при-слабои-защите" aria-label="Permalink to &quot;Какие риски возникают при слабой защите&quot;">​</a></h2><div class="card-grid"><div class="info-card"><h3>Потеря доступа</h3><p>Если злоумышленник получит доступ к аккаунту, владелец может временно или полностью потерять контроль над страницей.</p></div><div class="info-card"><h3>Утечка личной информации</h3><p>Личные сообщения, фотографии, список контактов и данные профиля могут стать доступны посторонним.</p></div><div class="info-card"><h3>Репутационный ущерб</h3><p>От имени владельца могут отправляться ложные сообщения, спам или недостоверные публикации.</p></div><div class="info-card"><h3>Цепная компрометация</h3><p>Один взломанный аккаунт нередко помогает добраться до других сервисов через функцию восстановления доступа.</p></div></div><h2 id="почему-обычные-пользователи-тоже-входят-в-группу-риска" tabindex="-1">Почему обычные пользователи тоже входят в группу риска <a class="header-anchor" href="#почему-обычные-пользователи-тоже-входят-в-группу-риска" aria-label="Permalink to &quot;Почему обычные пользователи тоже входят в группу риска&quot;">​</a></h2><ul><li>на них проще воздействовать за счет невнимательности;</li><li>пользователи часто повторно используют один и тот же пароль;</li><li>многие не включают двухфакторную аутентификацию;</li><li>в переписке могут храниться фотографии документов, коды и личные данные;</li><li>знакомые доверяют сообщениям от реального аккаунта и легче переходят по сомнительным ссылкам.</li></ul><div class="warning custom-block"><p class="custom-block-title">Важно помнить</p><p>Защита аккаунта строится не на одном действии, а на сочетании привычек: сильный пароль, 2FA, аккуратность со ссылками, проверка сеансов и разумная приватность.</p></div>',7)])])}const m=i(l,[["render",o]]);export{_ as __pageData,m as default};
